%[text] # Run samples of the ServiceQueue simulation --  Latherial Calbert & John McMann
%[text] Collect statistics and plot histograms along the way.
PictureFolder = "Pictures";
mkdir(PictureFolder); %[output:0688911a]
%%
%[text] ## Set up
%[text] We'll measure time in hours
%[text] Arrival rate: 10 per hour
lambda = 2;
%[text] Departure (service) rate: 1 per 5 minutes, so 12 per hour
%% 60/20
mu = 3;
%[text] Number of serving stations
%% one doctor
s = 1;
% 15 minutes = 0.25 per hour 1/.25
theta = 4 %[output:9caf3868]
%[text] Run many samples of the queue.
NumSamples = 20;
%[text] Each sample is run up to a maximum time.
MaxTime = 8;
%[text] Make a log entry every so often
LogInterval = 1/60;
%%
%[text] ## Numbers from theory for M/M/1 queue
%[text] Compute `P(1+n)` = $P\_n$ = probability of finding the system in state $n$ in the long term. Note that this calculation assumes $s=1$.
% rho = lambda / mu;
% P0 = 1 - rho;
% nMax = 10;
% P = zeros([1, nMax+1]);
% P(1) = P0;
% for n = 1:nMax
%     P(1+n) = P0 * rho^n;
% end

%%% calculate P0 - P5 for m/m/1 queue
P0 = 1/hypergeom([1], [mu/theta], lambda/theta);
nMax = 5;
P = zeros([nMax+1, 1]);
P(1) = P0;
for j = 1:nMax
    % Calculate the denominator using the product function
    denominator = prod(mu + (0:(j-1)) * theta);
    
    % Calculate the final probability for state j
    P(1+j) = P(1) * (lambda^j) / denominator;
end

%%% calculate pi_s

%%% theory pi_s and P0-P5
pi_s = (mu*(1-P0))/(lambda);



P(1) %[output:04ecd257]
P(2) %[output:08692397]
P(3) %[output:4b9963a3]
P(4) %[output:3af4bd36]
P(5) %[output:58603aa5]
P(6) %[output:71ed353d]
pi_s %[output:56333f40]
%%
%[text] ## Run simulation samples
%[text] This is the most time consuming calculation in the script, so let's put it in its own section.  That way, we can run it once, and more easily run the faster calculations multiple times as we add features to this script.
%[text] Reset the random number generator.  This causes MATLAB to use the same sequence of pseudo-random numbers each time you run the script, which means the results come out exactly the same.  This is a good idea for testing purposes.  Under other circumstances, you probably want the random numbers to be truly unpredictable and you wouldn't do this.
rng("default");
%[text] We'll store our queue simulation objects in this list.
QSamples = cell([NumSamples, 1]);
%[text] The statistics come out weird if the log interval is too short, because the log entries are not independent enough.  So the log interval should be long enough for several arrival and departure events happen.
for SampleNum = 1:NumSamples %[output:group:6757620f]
    if mod(SampleNum, 10) == 0
        fprintf("%d ", SampleNum); %[output:4808a02f]
    end
    if mod(SampleNum, 100) == 0
        fprintf("\n");
    end
    q = ServiceQueue( ...
        ArrivalRate=lambda, ...
        DepartureRate=mu, ...
        NumServers=s, ...
        LogInterval=LogInterval);
    q.schedule_event(Arrival(random(q.InterArrivalDist), Customer(1)));
    run_until(q, MaxTime);
    QSamples{SampleNum} = q;
end %[output:group:6757620f]
%%
%[text] ## Collect measurements of how many customers are in the system
%[text] Count how many customers are in the system at each log entry for each sample run.  There are two ways to do this.  You only have to do one of them.
%[text] ### Option one: Use a for loop.
NumInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % Pull out samples of the number of customers in the queue system. Each
    % sample run of the queue results in a column of samples of customer
    % counts, because tables like q.Log allow easy extraction of whole
    % columns like this.
    NumInSystemSamples{SampleNum} = q.Log.NumWaiting + q.Log.NumInService;
end
%[text] ### Option two: Map a function over the cell array of ServiceQueue objects.
%[text] The `@(q) ...` expression is shorthand for a function that takes a `ServiceQueue` as input, names it `q`, and computes the sum of two columns from its log.  The `cellfun` function applies that function to each item in `QSamples`. The option `UniformOutput=false` tells `cellfun` to produce a cell array rather than a numerical array.
NumInSystemSamples = cellfun( ...
    @(q) q.Log.NumWaiting + q.Log.NumInService, ...
    QSamples, ...
    UniformOutput=false);
%[text] ## Join numbers from all sample runs.
%[text] `vertcat` is short for "vertical concatenate", meaning it joins a bunch of arrays vertically, which in this case results in one tall column.
NumInSystem = vertcat(NumInSystemSamples{:});
%[text] MATLAB-ism: When you pull multiple items from a cell array, the result is a "comma-separated list" rather than some kind of array.  Thus, the above means
%[text] `NumInSystem = vertcat(NumInSystemSamples{1}, NumInSystemSamples{2}, ...)`
%[text] which concatenates all the columns of numbers in NumInSystemSamples into one long column.
%[text] This is roughly equivalent to "splatting" in Python, which looks like `f(*args)`.
%%
%[text] ## Pictures and stats for number of customers in system
%[text] Print out mean number of customers in the system.
meanNumInSystem = mean(NumInSystem);
fprintf("Mean number in system: %f\n", meanNumInSystem); %[output:3ae96bcc]
%[text] Make a figure with one set of axes.
fig = figure(); %[output:97111376]
t = tiledlayout(fig,1,1); %[output:97111376]
ax = nexttile(t); %[output:97111376]
%[text] MATLAB-ism: Once you've created a picture, you can use `hold` to cause further plotting functions to work with the same picture rather than create a new one.
hold(ax, "on"); %[output:97111376]
%[text] Start with a histogram.  The result is an empirical PDF, that is, the area of the bar at horizontal index n is proportional to the fraction of samples for which there were n customers in the system.  The data for this histogram is counts of customers, which must all be whole numbers.  The option `BinMethod="integers"` means to use bins $(-0.5, 0.5), (0.5, 1.5), \\dots$ so that the height of the first bar is proportional to the count of 0s in the data, the height of the second bar is proportional to the count of 1s, etc. MATLAB can choose bins automatically, but since we know the data consists of whole numbers, it makes sense to specify this option so we get consistent results.
h = histogram(ax, NumInSystem, Normalization="probability", BinMethod="integers"); %[output:97111376]
%[text] Plot $(0, P\_0), (1, P\_1), \\dots$.  If all goes well, these dots should land close to the tops of the bars of the histogram.
plot(ax, 0:nMax, P, 'o', MarkerEdgeColor='k', MarkerFaceColor='r'); %[output:97111376]
%[text] Add titles and labels and such.
title(ax, "Number of customers in the system"); %[output:97111376]
xlabel(ax, "Count"); %[output:97111376]
ylabel(ax, "Probability"); %[output:97111376]
legend(ax, "simulation", "theory"); %[output:97111376]
%[text] Set ranges on the axes. MATLAB's plotting functions do this automatically, but when you need to compare two sets of data, it's a good idea to use the same ranges on the two pictures.  To start, you can let MATLAB choose the ranges automatically, and just know that it might choose very different ranges for different sets of data.  Once you're certain the picture content is correct, choose an x range and a y range that gives good results for all sets of data.  The final choice of ranges is a matter of some trial and error.  You generally have to do these commands *after* calling `plot` and `histogram`.
%[text] This sets the vertical axis to go from $0$ to $0.2$.
ylim(ax, [0, 0.2]); %[output:97111376]
%[text] This sets the horizontal axis to go from $-1$ to $21$.  The histogram will use bins $(-0.5, 0.5), (0.5, 1.5), \\dots$ so this leaves some visual breathing room on the left.
xlim(ax, [-1, 21]); %[output:97111376]
%[text] MATLAB-ism: You have to wait a couple of seconds for those settings to take effect or `exportgraphics` will screw up the margins.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Number in system histogram.pdf"); %[output:97111376]
exportgraphics(fig, PictureFolder + filesep + "Number in system histogram.svg"); %[output:97111376]
%%
%[text] ## Collect measurements of how long customers spend in the system
%[text] This is a rather different calculation because instead of looking at log entries for each sample `ServiceQueue`, we'll look at the list of served  customers in each sample `ServiceQueue`.
%[text] ### Option one: Use a for loop.
TimeInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % The next command has many parts.
    %
    % q.Served is a row vector of all customers served in this particular
    % sample.
    % The ' on q.Served' transposes it to a column.
    %
    % The @(c) ... expression below says given a customer c, compute its
    % departure time minus its arrival time, which is how long c spent in
    % the system.
    %
    % cellfun(@(c) ..., q.Served') means to compute the time each customer
    % in q.Served spent in the system, and build a column vector of the
    % results.
    %
    % The column vector is stored in TimeInSystemSamples{SampleNum}.
    TimeInSystemSamples{SampleNum} = ...
        cellfun(@(c) c.DepartureTime - c.ArrivalTime, q.Served');
    TimeInWaitingSamples{SampleNum} = ...
        cellfun(@(c) c.BeginServiceTime - c.ArrivalTime, q.Served');
    TimeInServeSamples{SampleNum} = ...
        cellfun(@(c) c.DepartureTime- c.BeginServiceTime, q.Served');
end

%[text] ### Option two: Use `cellfun` twice.
%[text] The outer call to `cellfun` means do something to each `ServiceQueue` object in `QSamples`.  The "something" it does is to look at each customer in the `ServiceQueue` object's list `q.Served` and compute the time it spent in the system.
TimeInSystemSamples = cellfun( ...
    @(q) cellfun(@(c) c.DepartureTime - c.ArrivalTime, q.Served'), ...
    QSamples, ...
    UniformOutput=false);
%[text] ### Join them all into one big column.
TimeInSystem = vertcat(TimeInSystemSamples{:});
TimeInWait = vertcat(TimeInWaitingSamples{:});
TimeInServe = vertcat(TimeInServeSamples{:});
%%
%[text] ## Pictures and stats for time customers spend in the system
%[text] Print out mean time spent in the system.
meanTimeInSystem = mean(TimeInSystem);
fprintf("Mean time in system: %f\n", meanTimeInSystem); %[output:72a1b74b]
meanTimeWait = mean(TimeInWait);
fprintf("Mean time waiting in queue: %f\n", meanTimeWait); %[output:92b99c7e]

meanTimeServe = mean(TimeInServe);
fprintf("Mean time waiting in queue: %f\n", meanTimeServe); %[output:83d19598]
%[text] Make a figure with one set of axes.
fig = figure(); %[output:08ef075f]
t = tiledlayout(fig,1,1); %[output:08ef075f]
ax = nexttile(t); %[output:08ef075f]
%[text] This time, the data is a list of real numbers, not integers.  The option `BinWidth=...` means to use bins of a particular width, and choose the left-most and right-most edges automatically.  Instead, you could specify the left-most and right-most edges explicitly.  For instance, using `BinEdges=0:0.5:60` means to use bins $(0, 0.5), (0.5, 1.0), \\dots$
h = histogram(ax, TimeInSystem, Normalization="probability", BinWidth=5/60); %[output:08ef075f]
%[text] Add titles and labels and such.
title(ax, "Total Time in the System"); %[output:08ef075f]
xlabel(ax, "Time"); %[output:08ef075f]
ylabel(ax, "Probability"); %[output:08ef075f]
%[text] Set ranges on the axes.
ylim(ax, [0, 0.2]); %[output:08ef075f]
xlim(ax, [0, 2.0]); %[output:08ef075f]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:08ef075f]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:08ef075f]
fig = figure(); %[output:2f2b15dd]
t = tiledlayout(fig,1,1); %[output:2f2b15dd]
ax = nexttile(t); %[output:2f2b15dd]
h = histogram(ax, TimeInWait, Normalization="probability", BinWidth=5/60); %[output:2f2b15dd]
title(ax, "Time in Wait_Queue "); %[output:2f2b15dd]
xlabel(ax, "Time"); %[output:2f2b15dd]
ylabel(ax, "Probability"); %[output:2f2b15dd]
ylim(ax, [0, 0.2]); %[output:2f2b15dd]
xlim(ax, [0, 2.0]); %[output:2f2b15dd]
pause(2);
exportgraphics(fig, PictureFolder + filesep + "Time in Wait_Queue.pdf"); %[output:2f2b15dd]
exportgraphics(fig, PictureFolder + filesep + "Time in Wait_Queue.svg"); %[output:2f2b15dd]

fig = figure(); %[output:6a88984d]
t = tiledlayout(fig,1,1); %[output:6a88984d]
ax = nexttile(t); %[output:6a88984d]
h = histogram(ax, TimeInServe, Normalization="probability", BinWidth=5/60); %[output:6a88984d]
title(ax, "Time in Serve "); %[output:6a88984d]
xlabel(ax, "Time"); %[output:6a88984d]
ylabel(ax, "Probability"); %[output:6a88984d]
ylim(ax, [0, 0.2]); %[output:6a88984d]
xlim(ax, [0, 2.0]); %[output:6a88984d]
pause(2);
exportgraphics(fig, PictureFolder + filesep + "Time in Serve.pdf"); %[output:6a88984d]
exportgraphics(fig, PictureFolder + filesep + "Time in Serve.svg"); %[output:6a88984d]
NumInSystemSamples = cellfun( ...
    @(q) q.Log.NumWaiting + q.Log.NumInService, ...
    QSamples, ...
    UniformOutput=false);

NumWaitSamples = cellfun( ...
    @(q) q.Log.NumWaiting, ...
    QSamples, ...
    UniformOutput=false);

NumServeSamples = cellfun(@(q) q.Log.NumInService, QSamples, UniformOutput=false);

NumInSystem = vertcat(NumInSystemSamples{:});
NumLq = vertcat(NumWaitSamples{:});
NumInServe = vertcat(NumServeSamples{:});


meanNumInSystem = mean(NumInSystem);
fprintf("Mean number in system: %f\n", meanNumInSystem); %[output:3d544955]

meanLq = mean(NumLq);
fprintf("Mean number of customers waiting: %f\n", meanLq); %[output:129a17fc]

meanServe = mean(NumInServe);
fprintf("Mean number of customers in service: %f\n", meanServe); %[output:6257d626]


fig = figure(); %[output:7045869b]
t = tiledlayout(fig,1,1); %[output:7045869b]
ax = nexttile(t); %[output:7045869b]
hold(ax, "on"); %[output:7045869b]
h = histogram(ax, NumInSystem, Normalization="probability", BinMethod="integers"); %[output:7045869b]
% plot(ax, 0:nMax, P, 'o', MarkerEdgeColor='k', MarkerFaceColor='r');
title(ax, "Number of customers in the system"); %[output:7045869b]
xlabel(ax, "Count"); %[output:7045869b]
ylabel(ax, "Probability"); %[output:7045869b]
legend(ax, "simulation", "theory"); %[output:86ebe8e6] %[output:7045869b]
ylim(ax, [0, 0.3]); %[output:7045869b]
xlim(ax, [-1, 21]); %[output:7045869b]
pause(10);
exportgraphics(fig, "Number in system histogram.pdf"); %[output:7045869b]

fig = figure(); %[output:80cfc581]
t = tiledlayout(fig,1,1); %[output:80cfc581]
ax = nexttile(t); %[output:80cfc581]
hold(ax, "on"); %[output:80cfc581]
h = histogram(ax, NumLq, Normalization="probability", BinMethod="integers"); %[output:80cfc581]
% plot(ax, 0:nMax, P, 'o', MarkerEdgeColor='k', MarkerFaceColor='r');
title(ax, "Number of customers waiting"); %[output:80cfc581]
xlabel(ax, "Count"); %[output:80cfc581]
ylabel(ax, "Probability"); %[output:80cfc581]
legend(ax, "simulation", "theory"); %[output:5188fa17] %[output:80cfc581]
ylim(ax, [0, 0.3]); %[output:80cfc581]
xlim(ax, [-1, 21]); %[output:80cfc581]
pause(10);
exportgraphics(fig, "Number of customers waiting.pdf"); %[output:80cfc581]

fig = figure(); %[output:0b86b6dd]
t = tiledlayout(fig,1,1); %[output:0b86b6dd]
ax = nexttile(t); %[output:0b86b6dd]
hold(ax, "on"); %[output:0b86b6dd]
h = histogram(ax, NumInServe, Normalization="probability", BinMethod="integers"); %[output:0b86b6dd]
% plot(ax, 0:nMax, P, 'o', MarkerEdgeColor='k', MarkerFaceColor='r');
title(ax, "Number of customers served"); %[output:0b86b6dd]
xlabel(ax, "Count"); %[output:0b86b6dd]
ylabel(ax, "Probability"); %[output:0b86b6dd]
legend(ax, "simulation", "theory"); %[output:8a0fab4d] %[output:0b86b6dd]
ylim(ax, [0, 0.3]); %[output:0b86b6dd]
xlim(ax, [-1, 21]); %[output:0b86b6dd]
pause(10);
exportgraphics(fig, "Number of customers served.pdf"); %[output:0b86b6dd]



%%% Simulation
Wsim = meanTimeInSystem;
Wqsim = meanTimeWait;
Lsim = meanNumInSystem;
Lqsim = meanLq;
% 
% Mean number of customers waiting: 1.084841
% Mean number in system: 1.697442
% Mean time waiting in queue: 0.418945
% Mean time in system: 0.732087
%%% Theory
% W = 1
% Wq = 2/3 = .666
% L = 2
% Lq = 4/3 = 1.333

% Calculate theoretical values for comparison
W = 1; % Mean time in system (theory)
Wq = 2/3; % Mean time waiting in queue (theory)
L = 2; % Mean number in system (theory)
Lq = 4/3; % Mean number of customers waiting (theory)

%%% Theory P0-5 without reneging
P0noReneg = 1/3 %[output:2fd98bec]
P1noReneg = 2/9 %[output:177854d6]
P2noReneg = 4/27 %[output:22d001ec]
P3noReneg = (8/27)*(1/3) %[output:03a56479]
P4noReneg = ((2/3)^4)*(1/3) %[output:218e4eeb]
P5noReneg = ((2/3)^5)*(1/3) %[output:53d45119]

%%% Theory P0 with reneging
P0reneg = 0.5272 %[output:577a092a]
P1reneg = 0.3514 %[output:48c3ff84]
P2reneg = 0.1004 %[output:7648c32f]
P3reneg = 0.0183 %[output:97affb0f]
P4reneg = 0.0024 %[output:6967710f]
P5reneg = 0.00025624 %[output:54e41e96]

%%% Rel percent differences
relDiff.P0 = 100 * (P0reneg - P0noReneg) / P0noReneg;
relDiff.P1 = 100 * (P1reneg - P1noReneg) / P1noReneg;
relDiff.P2 = 100 * (P2reneg - P2noReneg) / P2noReneg;
relDiff.P3 = 100 * (P3reneg - P3noReneg) / P3noReneg;
relDiff.P4 = 100 * (P4reneg - P4noReneg) / P4noReneg;
relDiff.P5 = 100 * (P5reneg - P5noReneg) / P5noReneg;

relDiff.W  = 100 * (Wsim - W)  / W;
relDiff.Wq = 100 * (Wqsim - Wq) / Wq;
relDiff.L  = 100 * (Lsim - L)  / L;
relDiff.Lq = 100 * (Lqsim - Lq) / Lq;

fprintf("Relative percent differences (simulation vs theory):\n"); %[output:24f2c04e]
fprintf("  W  : %8.4f %%n", relDiff.W); %[output:4afed78c]
fprintf("  Wq : %8.4f %%n", relDiff.Wq); %[output:2b6820c7]
fprintf("  L  : %8.4f %%n", relDiff.L); %[output:6a9d7f15]
fprintf("  Lq : %8.4f %%n", relDiff.Lq); %[output:5a6edd37]




